import React, { useEffect, useMemo, useState } from 'react';
import '../../styles/storekeeper/storekeeper-layout.css';
import '../../styles/storekeeper/storekeeper-inventory.css';
import api from '../../services/api';
import { pushToast } from '../../utils/toastBridge'

const initialForm = {
  product_name: '',
  category_id: '',
  unit: '',
  supplier: '',
  description: '',
  status: 'ACTIVE',
};

const StorekeeperInventory = () => {
  const [products, setProducts] = useState([]);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(false);

  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('');
  const [selectedStatus, setSelectedStatus] = useState('');

  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [formData, setFormData] = useState(initialForm);

  useEffect(() => {
    fetchProducts();
    fetchCategories();
  }, []);

  const fetchProducts = async () => {
    try {
      setLoading(true);
      const params = new URLSearchParams();
      if (selectedCategory) params.append('categoryId', selectedCategory);
      if (selectedStatus) params.append('status', selectedStatus);
      if (searchTerm.trim()) params.append('search', searchTerm.trim());

      const query = params.toString();
      const res = await api.get(`/inventory/products${query ? `?${query}` : ''}`);
      setProducts(res.data?.data || []);
    } catch (err) {
      console.error('L�i khi t�i s�n ph�m:', err);
      pushToast({ title: 'Th�t b�i', message: 'Kh�ng th� t�i danh s�ch s�n ph�m', type: 'error' });
    } finally {
      setLoading(false);
    }
  };

  const fetchCategories = async () => {
    try {
      const res = await api.get('/inventory/categories');
      setCategories(res.data?.data || []);
    } catch (err) {
      console.error('L�i khi t�i danh m�c:', err);
    }
  };

  useEffect(() => {
    fetchProducts();
  }, [selectedCategory, selectedStatus]);

  const handleSearch = (e) => {
    e.preventDefault();
    fetchProducts();
  };

  const handleOpenModal = (product = null) => {
    if (product) {
      setEditingId(product.product_id);
      setFormData({
        product_name: product.product_name || '',
        category_id: String(product.category_id || ''),
        unit: product.unit || '',
        supplier: product.supplier || '',
        description: product.description || '',
        status: product.status || 'ACTIVE',
      });
    } else {
      setEditingId(null);
      setFormData(initialForm);
    }
    setShowModal(true);
  };

  const handleCloseModal = () => {
    setShowModal(false);
    setEditingId(null);
    setFormData(initialForm);
  };

  const resetForm = () => {
    handleCloseModal();
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      setLoading(true);

      const payload = {
        product_name: formData.product_name.trim(),
        category_id: Number(formData.category_id),
        unit: formData.unit.trim(),
        supplier: formData.supplier?.trim() || null,
        description: formData.description?.trim() || null,
        status: formData.status,
      };

      if (editingId) {
        await api.put(`/inventory/products/${editingId}`, payload);
      } else {
        await api.post('/inventory/products', payload);
      }

      resetForm();
      fetchProducts();
    } catch (err) {
      console.error('L�i khi l�u s�n ph�m:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (productId) => {
    const ok = window.confirm('B�n c� ch�c ch�n mu�n x�a s�n ph�m n�y?');
    if (!ok) return;

    try {
      setLoading(true);
      await api.delete(`/inventory/products/${productId}`);
      fetchProducts();
    } catch (err) {
      console.error('L�i khi x�a s�n ph�m:', err);
    } finally {
      setLoading(false);
    }
  };

  const getInventoryState = (product) => {
    const qty = Number(product.quantity || 0);
    const status = String(product.status || '').toUpperCase();

    if (status === 'INACTIVE') {
      return { label: 'Ng�ng s� d�ng', className: 'storekeeper-inventory__status--out' };
    }
    if (qty <= 0) {
      return { label: 'H�t h�ng', className: 'storekeeper-inventory__status--out' };
    }
    if (qty <= 20) {
      return { label: 'S�p h�t', className: 'storekeeper-inventory__status--low' };
    }
    return { label: 'C�n h�ng', className: 'storekeeper-inventory__status--in_stock' };
  };

  const inventoryStats = useMemo(() => {
    const inStock = products.filter((product) => getInventoryState(product).label === 'C�n h�ng').length;
    const lowStock = products.filter((product) => getInventoryState(product).label === 'S�p h�t').length;
    const inactive = products.filter((product) => String(product.status || '').toUpperCase() === 'INACTIVE').length;

    return {
      total: products.length,
      inStock,
      lowStock,
      inactive,
    };
  }, [products]);

  const categoryStats = useMemo(() => {
    const map = new Map();
    products.forEach((product) => {
      const name = product.category_name || 'Kh�c';
      const quantity = Number(product.quantity || 0);
